      {
        "scenario": "Scheduler stops picking up renewals (silent failure)",
        "handling": "unhandled",
        "recommendation": "The health check only tests billing API connectivity. A dead scheduler produces zero errors and zero logs — it simply stops working. Add a 'last renewal processed' heartbeat metric and alert if no renewals are processed for N minutes during business hours."
      },
